import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

const AdminDashboard = () => {
  const user = JSON.parse(localStorage.getItem("user") || "{}");
  const navigate = useNavigate();
  const [stats, setStats]       = useState({ users: 0, projects: 0, proposals: 0, freelancers: 0, clients: 0 });
  const [recent, setRecent]     = useState({ users: [], projects: [] });
  const [loading, setLoading]   = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const [statsRes, usersRes, projRes] = await Promise.all([
          API.get("/admin/dashboard"),
          API.get("/users/"),
          API.get("/projects/"),
        ]);
        const allUsers = usersRes.data || [];
        setStats({
          ...statsRes.data,
          freelancers: allUsers.filter(u => u.role === "freelancer").length,
          clients:     allUsers.filter(u => u.role === "client").length,
        });
        setRecent({
          users:    allUsers.slice(-5).reverse(),
          projects: (projRes.data || []).slice(-5).reverse(),
        });
      } catch (err) { console.error(err); }
      setLoading(false);
    };
    load();
  }, []);

  const statCards = [
    { label: "Total Users",     value: stats.users,      color: "border-blue-500",   text: "text-blue-600",   icon: "👥", link: "/admin/users" },
    { label: "Freelancers",     value: stats.freelancers, color: "border-teal-500",  text: "text-teal-600",   icon: "💻", link: "/admin/users" },
    { label: "Clients",         value: stats.clients,    color: "border-purple-500", text: "text-purple-600", icon: "🏢", link: "/admin/users" },
    { label: "Total Projects",  value: stats.projects,   color: "border-green-500",  text: "text-green-600",  icon: "📁", link: "/admin/projects" },
    { label: "Total Proposals", value: stats.proposals,  color: "border-orange-500", text: "text-orange-600", icon: "📄", link: "/admin/projects" },
    { label: "Platform",        value: "Active ✅",       color: "border-emerald-500",text: "text-emerald-600",icon: "🛡️", link: null },
  ];

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-6xl mx-auto">

        {/* HEADER */}
        <div className="mb-8">
          <h1 className="text-2xl font-bold text-gray-800">Admin Dashboard 🛡️</h1>
          <p className="text-gray-500 text-sm mt-1">Welcome back, {user.name} — Platform overview</p>
        </div>

        {/* STAT CARDS */}
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 mb-8">
          {statCards.map((s, i) => (
            <div key={i}
              onClick={() => s.link && navigate(s.link)}
              className={`bg-white rounded-xl p-5 shadow-sm border-l-4 ${s.color} ${s.link ? "cursor-pointer hover:shadow-md transition" : ""}`}>
              <div className="flex justify-between items-start">
                <div>
                  <p className="text-xs text-gray-500 mb-1">{s.label}</p>
                  <p className={`text-2xl font-bold ${s.text}`}>{s.value}</p>
                </div>
                <span className="text-2xl">{s.icon}</span>
              </div>
            </div>
          ))}
        </div>

        {/* RECENT ACTIVITY */}
        <div className="grid md:grid-cols-2 gap-6">

          {/* RECENT USERS */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-100">
            <div className="flex justify-between items-center p-5 border-b border-gray-100">
              <h2 className="font-bold text-gray-700">👥 Recent Users</h2>
              <button onClick={() => navigate("/admin/users")}
                className="text-sm text-teal-600 hover:text-teal-700 font-medium">View All →</button>
            </div>
            <div className="divide-y divide-gray-50">
              {recent.users.length === 0 ? (
                <p className="text-gray-400 text-sm p-5">No users yet.</p>
              ) : recent.users.map((u, i) => (
                <div key={i} className="flex items-center gap-3 px-5 py-3">
                  <div className="w-8 h-8 bg-teal-600 text-white rounded-full flex items-center justify-center text-sm font-bold flex-shrink-0">
                    {u.name?.charAt(0)?.toUpperCase()}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-800 truncate">{u.name}</p>
                    <p className="text-xs text-gray-400 truncate">{u.email}</p>
                  </div>
                  <span className={`text-xs px-2 py-0.5 rounded-full capitalize font-medium ${
                    u.role === "freelancer" ? "bg-teal-100 text-teal-700" :
                    u.role === "admin"      ? "bg-red-100 text-red-600" :
                    "bg-purple-100 text-purple-700"
                  }`}>{u.role}</span>
                </div>
              ))}
            </div>
          </div>

          {/* RECENT PROJECTS */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-100">
            <div className="flex justify-between items-center p-5 border-b border-gray-100">
              <h2 className="font-bold text-gray-700">📁 Recent Projects</h2>
              <button onClick={() => navigate("/admin/projects")}
                className="text-sm text-teal-600 hover:text-teal-700 font-medium">View All →</button>
            </div>
            <div className="divide-y divide-gray-50">
              {recent.projects.length === 0 ? (
                <p className="text-gray-400 text-sm p-5">No projects yet.</p>
              ) : recent.projects.map((p, i) => (
                <div key={i} className="flex items-center gap-3 px-5 py-3">
                  <div className="w-8 h-8 bg-green-600 text-white rounded-full flex items-center justify-center text-sm font-bold flex-shrink-0">
                    📁
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-800 truncate">{p.title}</p>
                    <p className="text-xs text-gray-400">₹{p.budget}</p>
                  </div>
                  <span className={`text-xs px-2 py-0.5 rounded-full capitalize font-medium ${
                    p.status === "closed" ? "bg-red-100 text-red-600" : "bg-green-100 text-green-600"
                  }`}>{p.status || "open"}</span>
                </div>
              ))}
            </div>
          </div>

        </div>

        {/* QUICK ACTIONS */}
        <div className="grid grid-cols-3 gap-4 mt-6">
          {[
            { icon: "👥", label: "Manage Users",    sub: "View & delete users",     link: "/admin/users" },
            { icon: "📁", label: "Manage Projects", sub: "View all projects",        link: "/admin/projects" },
            { icon: "📈", label: "Reports",          sub: "Platform statistics",     link: "/admin/reports" },
          ].map((a, i) => (
            <button key={i} onClick={() => navigate(a.link)}
              className="bg-white rounded-xl p-5 shadow-sm border border-gray-100 hover:shadow-md transition text-center">
              <div className="text-3xl mb-2">{a.icon}</div>
              <h3 className="font-bold text-gray-800 text-sm">{a.label}</h3>
              <p className="text-gray-400 text-xs mt-1">{a.sub}</p>
            </button>
          ))}
        </div>

      </div>
    </div>
  );
};

export default AdminDashboard;
